# encoding = utf-8import osimport sysimport timeimport jsonimport refrom obs import *from huawei_cloud_obs_tool import *def get_arg(param_dict, key):    value = param_dict.get(key.strip())    if isinstance(value, basestring):        return value.strip()    else:        return valuedef validate_input(helper, definition):    """Implement your own validation logic to validate the input stanza configurations"""    param_dict = definition.parameters    # helper.log_debug("Definition Parameters=%s" % param_dict)    # helper.log_debug("Definition metadata=%s" % definition.metadata)    bucket_name = get_arg(param_dict, "bucket_name")    if not re.match(r"^[a-z\d][a-z-.\d]{2,62}$", bucket_name):        raise ValueError("Bucket name(%s) is invalid!" % bucket_name)    timeout = get_arg(param_dict, "timeout")    if not re.match(r"^[1-9]\d*$", timeout):        raise ValueError("Http timeout value must be integer greater than 0!")def collect_events(helper, ew):    """Implement data collection logic"""        # helper.log_info("app_name: %s" % helper.get_app_name())    # helper.log_info("stanza_names: %s" % helper.get_input_stanza_names())        global_account_dict = helper.get_arg('global_account')    helper.log_info("Global Account: %s" % global_account_dict)    ak = global_account_dict["username"]    sk = global_account_dict['password']    # opt_region = helper.get_arg('region_name').strip()    _server = "https://obs.myhuaweicloud.com"    bucket_name = helper.get_arg('bucket_name').strip()    prefix = helper.get_arg('dir_prefix').strip()    if prefix:        prefix = prefix.strip().rstrip("/\\")        if prefix:            prefix += "/"    enable_deep_search = helper.get_arg("deep_search")    delimiter = None if enable_deep_search else "/"    obj_pattern = helper.get_arg("obj_pattern")    if obj_pattern:        obj_pattern = obj_pattern.strip()        helper.log_info("obj_pattern is: %s" % obj_pattern)    http_timeout = helper.get_arg("timeout")    if http_timeout is None:        http_timeout = 30    else:        http_timeout = int(http_timeout)    obs_client = ObsClient(ak, sk, server=_server, timeout=http_timeout)    with HuaweiCloudOBS(obs_client, helper) as obs_tool:        # if prefix:        #     resp_2 = obs_client.getObjectMetadata(bucket_name, prefix)        #     _msg_base = "Get metadata of target directory(%s) in bucket(%s)" % (prefix, bucket_name)        #     obs_tool.check_obsclient_response(resp_2, _msg_base)            valid_object_count = obs_tool.send_events(ew, bucket_name, prefix, delimiter, obj_pattern)        helper.log_debug("Indexed %d objects in bucket(%s) using pefix=%s and delimiter=%s" %                         (valid_object_count, bucket_name, prefix, delimiter))